import test from 'node:test';
import assert from 'node:assert/strict';
import { readFile } from 'node:fs/promises';

const registry = await readFile(new URL('../src/registry.js', import.meta.url), 'utf8');
const config = await readFile(new URL('../src/config.js', import.meta.url), 'utf8');

const expectedPolicy = {
  freeShippingCents: 5000,
  standardShippingCents: 700,
  taxRate: 0.08,
  checkoutRetry: 'pending',
};

test('published configuration matches the shared policy', () => Object.entries(expectedPolicy).forEach(([key, value]) => assert.ok(config.includes(`${key}: ${typeof value === 'string' ? `'${value}'` : value}`))));

test('A01 Foundation contribution is ready', () => assert.match(registry, /A01: \{.*status: 'ready'/));
test('A02 Design system contribution is ready', () => assert.match(registry, /A02: \{.*status: 'ready'/));
test('A03 Product data contribution is ready', () => assert.match(registry, /A03: \{.*status: 'ready'/));
test('A04 Catalog and PDP contribution is ready', () => assert.match(registry, /A04: \{.*status: 'ready'/));
test('A05 Search and facets contribution is ready', () => assert.match(registry, /A05: \{.*status: 'ready'/));
test('A06 Cart and pricing contribution is ready', () => assert.match(registry, /A06: \{.*status: 'ready'/));
test('A07 Wishlist contribution is ready', () => assert.match(registry, /A07: \{.*status: 'ready'/));
test('A08 Checkout contribution is ready', () => assert.match(registry, /A08: \{.*status: 'ready'/));
test('A09 Accessibility and performance contribution is ready', () => assert.match(registry, /A09: \{.*status: 'ready'/));
